  // src/gui/attribute_bar/components/LineWidthButton.ts
  var LINE_WIDTHS = [1, 2, 3, 4, 5];
  function createLineWidthButton(drawing, onChange, theme = "dark") {
    const isDark = theme === "dark";
    const wrapper = document.createElement("div");
    wrapper.style.cssText = "position: relative;";
    const btn = document.createElement("button");
    btn.innerHTML = ICONS2.lineStyle;
    btn.title = "Line width";
    btn.style.cssText = `
        display: flex;
        align-items: center;
        justify-content: center;
        width: 28px;
        height: 28px;
        background: transparent;
        border: none;
        color: ${isDark ? "#787b86" : "#131722"};
        cursor: pointer;
        border-radius: 4px;
        transition: all 0.1s ease;
    `;
    btn.addEventListener("mouseenter", () => {
      btn.style.background = isDark ? "#2a2e39" : "#e0e3eb";
      btn.style.color = isDark ? "#d1d4dc" : "#2962ff";
    });
    btn.addEventListener("mouseleave", () => {
      if (!popup) {
        btn.style.background = "transparent";
        btn.style.color = isDark ? "#787b86" : "#131722";
      }
    });
    let popup = null;
    let currentWidth = drawing.style.lineWidth || 2;
    const closePopup = () => {
      if (popup) {
        popup.remove();
        popup = null;
        btn.style.background = "transparent";
        btn.style.color = isDark ? "#787b86" : "#131722";
      }
    };
    const handleClickOutside = (e) => {
      if (!wrapper.contains(e.target)) {
        closePopup();
        document.removeEventListener("click", handleClickOutside);
      }
    };
    btn.addEventListener("click", (e) => {
      e.stopPropagation();
      if (popup) {
        closePopup();
        return;
      }
      popup = document.createElement("div");
      popup.style.cssText = `
            position: absolute;
            top: 100%;
            left: 50%;
            transform: translateX(-50%);
            margin-top: 8px;
            background: ${isDark ? "#1e222d" : "#ffffff"};
            border-radius: 8px;
            padding: 8px;
            box-shadow: 0 8px 32px rgba(0,0,0,${isDark ? "0.4" : "0.15"});
            border: ${isDark ? "none" : "1px solid #e0e3eb"};
            z-index: 10000;
            display: flex;
            flex-direction: column;
            gap: 4px;
        `;
      LINE_WIDTHS.forEach((width) => {
        const option = document.createElement("div");
        option.style.cssText = `
                display: flex;
                align-items: center;
                padding: 8px 12px;
                cursor: pointer;
                border-radius: 4px;
                transition: background 0.1s;
                gap: 12px;
            `;
        const linePreview = document.createElement("div");
        linePreview.style.cssText = `
                width: 40px;
                height: ${width}px;
                background: ${isDark ? "#d1d4dc" : "#787b86"};
                border-radius: 1px;
            `;
        const label = document.createElement("span");
        label.textContent = `${width}px`;
        label.style.cssText = `
                font-size: 12px;
                color: ${isDark ? "#787b86" : "#131722"};
            `;
        const check = document.createElement("span");
        check.innerHTML = width === currentWidth ? `<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#2962ff" stroke-width="3"><polyline points="20 6 9 17 4 12"/></svg>` : "";
        check.style.cssText = "margin-left: auto;";
        option.appendChild(linePreview);
        option.appendChild(label);
        option.appendChild(check);
        option.addEventListener("mouseenter", () => {
          option.style.background = isDark ? "#2a2e39" : "#f0f3fa";
        });
        option.addEventListener("mouseleave", () => {
          option.style.background = "transparent";
        });
        option.addEventListener("click", () => {
          currentWidth = width;
          drawing.style.lineWidth = width;
          onChange(width);
          closePopup();
        });
        popup.appendChild(option);
      });
      wrapper.appendChild(popup);
      setTimeout(() => document.addEventListener("click", handleClickOutside), 10);
    });
    wrapper.appendChild(btn);
    return wrapper;
  }

  // src/gui/attribute_bar/BaseAttributeBar.ts
  var BaseAttributeBar = class {
    constructor(container) {
      this._element = null;
      this._isVisible = false;
      this._currentDrawing = null;
      this._theme = "dark";
      // Drag state
      this._isDragging = false;
      this._dragStartX = 0;
      this._dragStartY = 0;
      this._elementStartX = 0;
      this._elementStartY = 0;
      // Events
      this.colorChanged = new Delegate();
      this.lineWidthChanged = new Delegate();
      this.lineStyleChanged = new Delegate();
      this.deleteClicked = new Delegate();
      this.lockClicked = new Delegate();
      this.cloneClicked = new Delegate();
      this.settingsClicked = new Delegate();
      this._boundMouseMove = this._onMouseMove.bind(this);
      this._boundMouseUp = this._onMouseUp.bind(this);
      this._createElement(container);
    }
    // --- Public API ---
    setTheme(theme) {
      if (this._theme === theme) return;
      this._theme = theme;
      if (this._element) {
        const isDark = theme === "dark";
        this._element.style.background = isDark ? "#1e222d" : "#ffffff";
        this._element.style.boxShadow = isDark ? "0 4px 20px rgba(0,0,0,0.4)" : "0 4px 20px rgba(0,0,0,0.15)";
        this._element.style.border = isDark ? "none" : "1px solid #e0e3eb";
      }
      if (this._isVisible && this._currentDrawing) {
        this._rebuildForDrawingType(this._currentDrawing.type);
      }
    }
    show(drawing) {
      if (!this._element) return;
      this._currentDrawing = drawing;
      this._rebuildForDrawingType(drawing.type);
      this._element.style.display = "flex";
      this._isVisible = true;
    }
    hide() {
      if (!this._element) return;
      this._element.style.display = "none";
      this._isVisible = false;
      this._currentDrawing = null;
    }
    isVisible() {
      return this._isVisible;
    }
    dispose() {
      document.removeEventListener("mousemove", this._boundMouseMove);
      document.removeEventListener("mouseup", this._boundMouseUp);
      this.colorChanged.destroy();
      this.lineWidthChanged.destroy();
      this.lineStyleChanged.destroy();
      this.deleteClicked.destroy();
      this.lockClicked.destroy();
      this.cloneClicked.destroy();
      this.settingsClicked.destroy();
      if (this._element?.parentNode) {
        this._element.parentNode.removeChild(this._element);
      }
      this._element = null;
    }
    // --- Protected: Bar Building ---
    _rebuildForDrawingType(drawingType) {
      if (!this._element) return;
      this._element.innerHTML = "";
      this._addDragHandle();
      switch (drawingType) {
        case "fibRetracement":
        case "fibExtension":
        case "fibChannel":
          this._buildFibonacciBar();
          break;
        case "trendLine":
        case "ray":
        case "extendedLine":
          this._buildTrendLineBar();
          break;
        case "horizontalLine":
        case "verticalLine":
          this._buildSimpleLineBar();
          break;
        case "rectangle":
        case "ellipse":
          this._buildShapeBar();
          break;
        case "parallelChannel":
          this._buildChannelBar();
          break;
        default:
          this._buildDefaultBar();
      }
    }
    _buildFibonacciBar() {
      this._addTemplateButton();
      this._addSeparator();
      this._addColorButton();
      this._addLineWidthButton();
      this._addSeparator();
      this._addSettingsButton();
      this._addLockButton();
      this._addSeparator();
      this._addDeleteButton();
      this._addMoreButton();
    }
    _buildTrendLineBar() {
      this._addTemplateButton();
      this._addSeparator();
      this._addColorButton();
      this._addTextColorButton();
      this._addLineWidthButton();
      this._addSeparator();
      this._addSettingsButton();
      this._addLockButton();
      this._addSeparator();
      this._addDeleteButton();
      this._addMoreButton();
    }
    _buildSimpleLineBar() {
      this._addColorButton();
      this._addLineWidthButton();
      this._addSeparator();
      this._addLockButton();
      this._addDeleteButton();
    }
    _buildShapeBar() {
      this._addColorButton("color", "Border Color");
      this._addColorButton("fillColor", "Background Color");
      this._addLineWidthButton();
      this._addSeparator();
      this._addSettingsButton();
      this._addLockButton();
      this._addDeleteButton();
    }
    _buildChannelBar() {
      this._addColorButton();
      this._addLineWidthButton();
      this._addSeparator();
      this._addSettingsButton();
      this._addLockButton();
      this._addDeleteButton();
    }
    _buildDefaultBar() {
      this._addColorButton();
      this._addLineWidthButton();
      this._addSeparator();
      this._addLockButton();
      this._addDeleteButton();
    }
    // --- Protected: Button Helpers ---
    _addDragHandle() {
      if (!this._element) return;
      const btn = createToolbarButton(
        { icon: ICONS2.drag, title: "Move toolbar", className: "drag-handle", theme: this._theme },
        () => {
        }
      );
      btn.style.cursor = "grab";
      btn.addEventListener("mousedown", (e) => {
        btn.style.cursor = "grabbing";
        this._onDragStart(e);
      });
      btn.addEventListener("mouseup", () => {
        btn.style.cursor = "grab";
      });
      this._element.appendChild(btn);
    }
    _addTemplateButton() {
      if (!this._element) return;
      const btn = createToolbarButton(
        { icon: ICONS2.template, title: "Template", theme: this._theme },
        () => this.settingsClicked.fire()
      );
      this._element.appendChild(btn);
    }
    _addSeparator() {
      if (!this._element) return;
      const sep = createSeparator();
      if (this._theme === "light") {
        sep.style.borderLeftColor = "#e0e3eb";
      }
      this._element.appendChild(sep);
    }
    _addColorButton(property = "color", title = "Color") {
      if (!this._element || !this._currentDrawing) return;
      const icon = property === "fillColor" ? ICONS2.fillBucket : ICONS2.pencil;
      const colorBtn = createColorButton(
        this._currentDrawing,
        { property, icon, title, theme: this._theme },
        (color) => this.colorChanged.fire(color)
      );
      this._element.appendChild(colorBtn);
    }
    _addLineWidthButton() {
      if (!this._element || !this._currentDrawing) return;
      const btn = createLineWidthButton(
        this._currentDrawing,
        (width) => this.lineWidthChanged.fire(width),
        this._theme
      );
      this._element.appendChild(btn);
    }
    _addTextColorButton() {
      if (!this._element || !this._currentDrawing) return;
      const colorBtn = createColorButton(
        this._currentDrawing,
        { property: "textColor", icon: ICONS2.textColor, title: "Text Color", theme: this._theme },
        (color) => this.colorChanged.fire(color)
      );
      this._element.appendChild(colorBtn);
    }
    _addSettingsButton() {
      if (!this._element) return;
      const btn = createToolbarButton(
        { icon: ICONS2.settings, title: "Settings", theme: this._theme },
        () => this.settingsClicked.fire()
      );
      this._element.appendChild(btn);
    }
    _addLockButton() {
      if (!this._element) return;
      const btn = createToolbarButton(
        { icon: ICONS2.lock, title: "Lock drawing", theme: this._theme },
        () => this.lockClicked.fire()
      );
      this._element.appendChild(btn);
    }
    _addDeleteButton() {
      if (!this._element) return;
      const btn = createToolbarButton(
        { icon: ICONS2.delete, title: "Delete", isDestructive: true, theme: this._theme },
        () => this.deleteClicked.fire()
      );
      this._element.appendChild(btn);
    }
    _addMoreButton() {
      if (!this._element) return;
      const btn = createToolbarButton(
        { icon: ICONS2.more, title: "More options", theme: this._theme },
        () => {
        }
      );
      this._element.appendChild(btn);
    }
    // --- Private: Element Creation ---
    _createElement(container) {
      this._element = document.createElement("div");
      this._element.style.cssText = `
            position: absolute;
            top: 60px;
            left: 50%;
            transform: translateX(-50%);
            display: none;
            align-items: center;
            background: #1e222d;
            border-radius: 6px;
            padding: 4px 8px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.4);
            z-index: 2000;
            gap: 2px;
        `;
      container.appendChild(this._element);
    }
    // --- Private: Drag Handling ---
    _onDragStart(e) {
      if (!this._element) return;
      this._isDragging = true;
      this._dragStartX = e.clientX;
      this._dragStartY = e.clientY;
      const rect = this._element.getBoundingClientRect();
      this._elementStartX = rect.left;
      this._elementStartY = rect.top;
      document.addEventListener("mousemove", this._boundMouseMove);
      document.addEventListener("mouseup", this._boundMouseUp);
    }
    _onMouseMove(e) {
      if (!this._isDragging || !this._element) return;
      const dx = e.clientX - this._dragStartX;
      const dy = e.clientY - this._dragStartY;
      this._element.style.left = `${this._elementStartX + dx}px`;
      this._element.style.top = `${this._elementStartY + dy}px`;
      this._element.style.transform = "none";
    }
    _onMouseUp() {
      this._isDragging = false;
      document.removeEventListener("mousemove", this._boundMouseMove);
      document.removeEventListener("mouseup", this._boundMouseUp);
    }
  };

