  // src/gui/settings_modal/generic/GenericSettingsModal.ts
  var DRAWING_TITLES = {
    trendLine: "Trend Line",
    horizontalLine: "Horizontal Line",
    verticalLine: "Vertical Line",
    ray: "Ray",
    infoLine: "Info Line",
    extendedLine: "Extended Line",
    trendAngle: "Trend Angle",
    horizontalRay: "Horizontal Ray",
    crossLine: "Cross Line",
    parallelChannel: "Parallel Channel",
    rectangle: "Rectangle",
    ellipse: "Ellipse",
    brush: "Brush",
    highlighter: "Highlighter",
    arrow: "Arrow",
    arrowMarker: "Arrow Marker",
    arrowMarkedUp: "Arrow Marked Up",
    arrowMarkedDown: "Arrow Marked Down"
  };
  var GenericSettingsModal = class extends BaseSettingsModal {
    constructor() {
      super(...arguments);
      this._settingsConfig = null;
    }
    /** Get modal title */
    getTitle() {
      if (!this._currentDrawing) return t("Settings");
      const title = DRAWING_TITLES[this._currentDrawing.type];
      return title ? t(title) : t("Drawing Settings");
    }
    /** Initialize by reading settings config from drawing */
    initializeForDrawing(drawing) {
      if (this._isSettingsProvider(drawing)) {
        this._settingsConfig = drawing.getSettingsConfig();
      } else {
        this._settingsConfig = null;
      }
      const lineBasedTypes = [
        "trendLine",
        "ray",
        "extendedLine",
        "horizontalLine",
        "verticalLine",
        "parallelChannel",
        "trendAngle",
        "horizontalRay",
        "infoLine"
      ];
      if (lineBasedTypes.includes(drawing.type)) {
        this.getTabs = () => [
          { id: "style", label: t("Style") },
          { id: "text", label: t("Text") },
          { id: "coordinates", label: t("Coordinates") },
          { id: "visibility", label: t("Visibility") }
        ];
      } else {
        delete this.getTabs;
      }
    }
    /** Check if drawing implements DrawingSettingsProvider */
    _isSettingsProvider(drawing) {
      return "getSettingsConfig" in drawing && "getSettingValue" in drawing && "setSettingValue" in drawing;
    }
    /** Render tab content based on tab ID */
    renderTabContent(tabId, container) {
      switch (tabId) {
        case "style":
          this._renderStyleTab(container);
          break;
        case "coordinates":
          this._renderCoordinatesTab(container);
          break;
        case "text":
          this._renderTextTab(container);
          break;
        case "visibility":
          this._renderVisibilityTab(container);
          break;
      }
    }
    /** Render style tab - either from config or using section components */
    _renderStyleTab(container) {
      if (!this._currentDrawing) return;
      if (this._settingsConfig && this._isSettingsProvider(this._currentDrawing)) {
        const styleTab = this._settingsConfig.tabs.find((t2) => t2.id === "style");
        if (styleTab) {
          this._renderSectionsFromConfig(container, styleTab.sections, this._currentDrawing);
          return;
        }
      }
      this._renderDefaultStyleTab(container);
    }
    _renderSectionsFromConfig(container, sections, provider) {
      sections.forEach((section) => {
        const sectionEl = createSection(t(section.title), (content) => {
          section.rows.forEach((row) => {
            if (isGroupRow(row)) {
              const groupEl = document.createElement("div");
              groupEl.style.cssText = "display: flex; align-items: center; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid var(--border-color);";
              if (row.label) {
                const labelEl = document.createElement("span");
                labelEl.textContent = t(row.label);
                labelEl.style.cssText = "font-size: 13px; color: var(--text-primary);";
                groupEl.appendChild(labelEl);
              }
              const controlsWrapper = document.createElement("div");
              controlsWrapper.style.cssText = "display: flex; align-items: center; gap: 8px;";
              row.rows.forEach((subRow) => {
                const ctrl = this._createControlForRow(subRow, provider);
                if (ctrl) controlsWrapper.appendChild(ctrl);
              });
              groupEl.appendChild(controlsWrapper);
              content.appendChild(groupEl);
              return;
            }
            if (isToggleColorRow(row)) {
              const rowEl = document.createElement("div");
              rowEl.style.cssText = "display: flex; align-items: center; justify-content: space-between; padding: 10px 0; border-bottom: 1px solid var(--border-color);";
              const checked = provider.getSettingValue(row.toggleKey);
              const checkbox = createCheckbox2(checked ?? false, row.label, (val) => {
                provider.setSettingValue(row.toggleKey, val);
                this.notifySettingsChanged();
              });
              rowEl.appendChild(checkbox);
              const color = provider.getSettingValue(row.colorKey);
              const swatch = createColorSelect(color || "#000000", (val) => {
                provider.setSettingValue(row.colorKey, val);
                this.notifySettingsChanged();
              });
              rowEl.appendChild(swatch);
              content.appendChild(rowEl);
              return;
            }
            if (isTextareaRow(row)) {
              const val = provider.getSettingValue(row.key);
              const ctrl = createTextArea(val || "", "", (newVal) => {
                provider.setSettingValue(row.key, newVal);
                this.notifySettingsChanged();
              });
              const rowEl = document.createElement("div");
              rowEl.style.cssText = "padding: 10px 0; border-bottom: 1px solid var(--border-color);";
              rowEl.appendChild(ctrl);
              content.appendChild(rowEl);
              return;
            }
            if (isLevelsGridRow(row)) {
              const currentLevels = provider.getSettingValue(row.key) || [];
              const normalizedLevels = currentLevels.map((level) => ({
                level: level.level,
                label: level.label,
                color: level.color,
                visible: level.visible ?? level.enabled ?? true
              }));
              const editor = createFibLevelsEditor(normalizedLevels, (updatedLevels) => {
                const mappedLevels = updatedLevels.map((level) => ({
                  level: level.level,
                  label: level.label,
                  color: level.color,
                  enabled: level.visible
                }));
                provider.setSettingValue(row.key, mappedLevels);
                this.notifySettingsChanged();
              });
              const rowEl = document.createElement("div");
              rowEl.style.cssText = "padding: 10px 0; border-bottom: 1px solid var(--border-color);";
              rowEl.appendChild(editor);
              content.appendChild(rowEl);
              return;
            }
            const control = this._createControlForRow(row, provider);
            if (control) {
              const rowEl = createSettingsRow(row.label ? t(row.label) : "", control);
              content.appendChild(rowEl);
            }
          });
        });
        container.appendChild(sectionEl);
      });
    }
    _createControlForRow(row, provider) {
      if (isGroupRow(row) || isToggleColorRow(row) || isTextareaRow(row) || isLevelsGridRow(row)) return null;
      const currentValue = provider.getSettingValue(row.key);
      if (isColorRow(row)) {
        return createColorSelect(currentValue || "#2962ff", (color) => {
          provider.setSettingValue(row.key, color);
          this.notifySettingsChanged();
        });
      }
      if (isNumberRow(row)) {
        return createNumberInput2(
          currentValue ?? row.min ?? 1,
          row.min ?? 0,
          row.max ?? 100,
          row.step ?? 1,
          (value) => {
            provider.setSettingValue(row.key, value);
            this.notifySettingsChanged();
          }
        );
      }
      if (isSliderRow(row)) {
        return createSliderInput2(
          currentValue ?? row.min,
          row.min,
          row.max,
          row.step ?? 1,
          row.suffix ?? "",
          (value) => {
            provider.setSettingValue(row.key, value);
            this.notifySettingsChanged();
          }
        );
      }
      if (isCheckboxRow(row)) {
        return createCheckbox2(currentValue ?? false, "", (checked) => {
          provider.setSettingValue(row.key, checked);
          this.notifySettingsChanged();
        });
      }
      if (isLineStyleRow(row)) {
        const style = currentValue || "solid";
        return createLineStyleSelect(style, (newStyle) => {
          provider.setSettingValue(row.key, newStyle);
          this.notifySettingsChanged();
        });
      }
      if (isLineWidthRow(row)) {
        return createLineWidthSelect2(currentValue ?? 2, (width) => {
          provider.setSettingValue(row.key, width);
          this.notifySettingsChanged();
        });
      }
      if (isSelectRow(row)) {
        return createSelect(row.options, currentValue ?? "", (value) => {
          provider.setSettingValue(row.key, value);
          this.notifySettingsChanged();
        });
      }
      return null;
    }
    /** Fallback: render default style tab using section components */
    _renderDefaultStyleTab(container) {
      const drawing = this._currentDrawing;
      if (!drawing) return;
      const borderSection = createBorderSection(drawing, () => this.notifySettingsChanged());
      container.appendChild(borderSection);
      const bgSection = createBackgroundSection(drawing, () => this.notifySettingsChanged());
      if (bgSection) {
        container.appendChild(bgSection);
      }
    }
    /** Render coordinates tab using section component */
    _renderCoordinatesTab(container) {
      const drawing = this._currentDrawing;
      if (!drawing) return;
      const pointsSection = createPointsSection(drawing);
      container.appendChild(pointsSection);
    }
    /** Render visibility tab using section component */
    _renderVisibilityTab(container) {
      const drawing = this._currentDrawing;
      if (!drawing) return;
      const visibilitySection = createVisibilitySection(drawing, () => this.notifySettingsChanged());
      container.appendChild(visibilitySection);
    }
    /** Render text tab for line-based drawings */
    _renderTextTab(container) {
      const drawing = this._currentDrawing;
      if (!drawing) return;
      const textSection = createTextSection(drawing, () => this.notifySettingsChanged());
      container.appendChild(textSection);
    }
  };

  // src/gui/settings_modal/index.ts
  var CUSTOM_MODAL_TYPES = [
    "fibRetracement",
    "fibExtension",
    "fibChannel"
  ];
  function createSettingsModal(container, drawing) {
    const type = drawing.type;
    if (CUSTOM_MODAL_TYPES.includes(type)) {
      return new GenericSettingsModal(container);
    }
    return new GenericSettingsModal(container);
  }

  // src/state/chart-state-manager.ts
  var LocalStorageAdapter = class {
    constructor(prefix = "chart_") {
      this._prefix = prefix;
    }
    save(key, data) {
      try {
        localStorage.setItem(this._prefix + key, data);
      } catch (e) {
        console.error("Failed to save to localStorage:", e);
      }
    }
    load(key) {
      try {
        return localStorage.getItem(this._prefix + key);
      } catch (e) {
        console.error("Failed to load from localStorage:", e);
        return null;
      }
    }
    delete(key) {
      try {
        localStorage.removeItem(this._prefix + key);
      } catch (e) {
        console.error("Failed to delete from localStorage:", e);
      }
    }
    keys() {
      const keys = [];
      try {
        for (let i = 0; i < localStorage.length; i++) {
          const key = localStorage.key(i);
          if (key && key.startsWith(this._prefix)) {
            keys.push(key.substring(this._prefix.length));
          }
        }
      } catch (e) {
        console.error("Failed to list keys from localStorage:", e);
      }
      return keys;
    }
  };
  var CURRENT_VERSION = 1;
  var ChartStateManager = class {
    constructor(drawingManager, indicatorManager, storage) {
      this._currentSymbol = "";
      this._autoSave = true;
      this._saveDebounceTimer = null;
      this._drawingManager = drawingManager;
      this._indicatorManager = indicatorManager;
      this._storage = storage || new LocalStorageAdapter();
      this._drawingManager.drawingsChanged.subscribe(() => {
        if (this._autoSave && this._currentSymbol) {
          this._debouncedSave();
        }
      });
      const saveHandler = () => {
        if (this._autoSave && this._currentSymbol) {
          this._debouncedSave();
        }
      };
      this._indicatorManager.onIndicatorAdded = saveHandler;
      this._indicatorManager.onIndicatorRemoved = saveHandler;
    }
    // =========================================================================
    // Public Methods
    // =========================================================================
    /** Set current symbol and load its state */
    setSymbol(symbol) {
      if (this._currentSymbol && this._currentSymbol !== symbol) {
        this.saveState();
      }
      this._currentSymbol = symbol;
      this.loadState();
    }
    /** Get current symbol */
    get currentSymbol() {
      return this._currentSymbol;
    }
    /** Enable/disable auto-save */
    set autoSave(enabled) {
      this._autoSave = enabled;
    }
    get autoSave() {
      return this._autoSave;
    }
    /** Manually save current state */
    saveState() {
      if (!this._currentSymbol) return;
      const drawingState = {
        symbol: this._currentSymbol,
        drawings: this._drawingManager.serialize(),
        savedAt: Date.now(),
        version: CURRENT_VERSION
      };
      this._storage.save(this._currentSymbol, JSON.stringify(drawingState));
      this._saveIndicatorsGlobal();
      console.log(
        `Chart state saved for ${this._currentSymbol}:`,
        drawingState.drawings.length,
        "drawings"
      );
    }
    /** Save indicators globally (not per-symbol) */
    _saveIndicatorsGlobal() {
      const indicatorState = {
        indicators: this._indicatorManager.serialize(),
        savedAt: Date.now(),
        version: CURRENT_VERSION
      };
      this._storage.save("_layout_indicators", JSON.stringify(indicatorState));
      console.log(`Indicators saved globally:`, indicatorState.indicators.length, "indicators");
    }
    /** Manually load state for current symbol */
    loadState() {
      if (!this._currentSymbol) return;
      const drawingJson = this._storage.load(this._currentSymbol);
      if (drawingJson) {
        try {
          const state = JSON.parse(drawingJson);
          this._drawingManager.deserialize(state.drawings || []);
          console.log(`Drawings loaded for ${this._currentSymbol}:`, state.drawings?.length || 0);
        } catch (e) {
          console.error("Failed to parse saved drawings:", e);
          this._drawingManager.deserialize([]);
        }
      } else {
        this._drawingManager.deserialize([]);
      }
      if (this._indicatorManager.allIndicators.length === 0) {
        this._loadIndicatorsGlobal();
      }
    }
    /** Load indicators from global storage */
    _loadIndicatorsGlobal() {
      const indicatorJson = this._storage.load("_layout_indicators");
      if (!indicatorJson) {
        console.log("No saved indicators");
        return;
      }
      try {
        const state = JSON.parse(indicatorJson);
        this._indicatorManager.deserialize(state.indicators || []);
        console.log(`Indicators loaded globally:`, state.indicators?.length || 0);
      } catch (e) {
        console.error("Failed to parse saved indicators:", e);
      }
    }
    /** Delete saved state for a symbol */
    deleteState(symbol) {
      const targetSymbol = symbol || this._currentSymbol;
      if (targetSymbol) {
        this._storage.delete(targetSymbol);
        console.log(`Chart state deleted for ${targetSymbol}`);
      }
    }
    /** Get list of symbols with saved states */
    getSavedSymbols() {
      return this._storage.keys();
    }
    /** Check if a symbol has saved state */
    hasState(symbol) {
      const targetSymbol = symbol || this._currentSymbol;
      return targetSymbol ? this._storage.load(targetSymbol) !== null : false;
    }
    /** Export state for backup */
    exportState(symbol) {
      const targetSymbol = symbol || this._currentSymbol;
      if (!targetSymbol) return null;
      return this._storage.load(targetSymbol);
    }
    /** Import state from backup */
    importState(json, symbol) {
      const targetSymbol = symbol || this._currentSymbol;
      if (!targetSymbol) return false;
      try {
        const state = JSON.parse(json);
        if (!state.drawings || !Array.isArray(state.drawings)) {
          throw new Error("Invalid state format");
        }
        this._storage.save(targetSymbol, json);
        if (targetSymbol === this._currentSymbol) {
          this.loadState();
        }
        return true;
      } catch (e) {
        console.error("Failed to import state:", e);
        return false;
      }
    }
    // =========================================================================
    // Private Methods
    // =========================================================================
    /** Debounced save to prevent excessive writes */
    _debouncedSave() {
      if (this._saveDebounceTimer !== null) {
        clearTimeout(this._saveDebounceTimer);
      }
      this._saveDebounceTimer = window.setTimeout(() => {
        this.saveState();
        this._saveDebounceTimer = null;
      }, 500);
    }
    /** Cleanup */
    destroy() {
      if (this._saveDebounceTimer !== null) {
        clearTimeout(this._saveDebounceTimer);
      }
    }
  };

  // src/gui/tooltips/AddTextTooltipHelper.ts
  var AddTextTooltipHelper = class {
    constructor(onClick) {
      this._element = null;
      this._theme = "dark";
      this._onClick = onClick;
    }
    setTheme(theme) {
      this._theme = theme;
      if (this._element) {
        this._updateStyle();
      }
    }
    /**
     * Show tooltip at the specified screen position with rotation
     */
    show(screenX, screenY, rotationDeg = 0) {
      if (!this._element) {
        this._createElement();
      }
      this._element.style.left = `${screenX}px`;
      this._element.style.top = `${screenY}px`;
      this._element.style.transform = `translate(-50%, -50%) rotate(${rotationDeg}deg)`;
      this._element.style.display = "block";
    }
    /**
     * Hide the tooltip
     */
    hide() {
      if (this._element) {
        this._element.style.display = "none";
      }
    }
    /**
     * Dispose and remove the tooltip element
     */
    dispose() {
      if (this._element) {
        this._element.remove();
        this._element = null;
      }
    }
    // --- Private ---
    _createElement() {
      this._element = document.createElement("div");
      this._element.className = "add-text-tooltip";
      this._updateStyle();
      this._element.textContent = t("+ Add Text");
      this._element.addEventListener("click", (e) => {
        e.stopPropagation();
        this._onClick();
        this.hide();
      });
      document.body.appendChild(this._element);
    }
    _updateStyle() {
      if (!this._element) return;
      const isDark = this._theme === "dark";
      const shadow = isDark ? "0 0 4px rgba(0,0,0,0.8)" : "0 0 4px rgba(255,255,255,1)";
      const color = isDark ? "#787B86" : "#2962ff";
      this._element.style.cssText = `
            position: fixed;
            padding: 2px 4px;
            background: transparent;
            color: ${color};
            font-size: 12px;
            font-weight: 400;
            cursor: pointer;
            pointer-events: auto;
            white-space: nowrap;
            z-index: 10000;
            text-shadow: ${shadow};
            transform: translate(-50%, -50%);
            user-select: none;
            display: ${this._element.style.display || "none"};
            left: ${this._element.style.left};
            top: ${this._element.style.top};
        `;
    }
  };

  // src/services/technical-rating-service.ts
  function getRatingLabel(rating) {
    if (rating <= -0.5) {
      return { text: t("Strong Sell"), color: "#ffffff", bgColor: "#ef5350" };
    } else if (rating <= -0.1) {
      return { text: t("Sell"), color: "#ffffff", bgColor: "#ff7043" };
    } else if (rating <= 0.1) {
      return { text: t("Neutral"), color: "#131722", bgColor: "#9e9e9e" };
    } else if (rating <= 0.5) {
      return { text: t("Buy"), color: "#ffffff", bgColor: "#66bb6a" };
    } else {
      return { text: t("Strong Buy"), color: "#ffffff", bgColor: "#26a69a" };
    }
  }
  async function fetchTechnicalRating(symbol, exchange = "BINANCE", timeframe = "") {
    let tvTimeframe = "";
    switch (timeframe) {
      case "1m":
        tvTimeframe = "|1";
        break;
      case "5m":
        tvTimeframe = "|5";
        break;
      case "15m":
        tvTimeframe = "|15";
        break;
      case "30m":
        tvTimeframe = "|30";
        break;
      case "1h":
        tvTimeframe = "|60";
        break;
      case "2h":
        tvTimeframe = "|120";
        break;
      case "4h":
        tvTimeframe = "|240";
        break;
      case "D":
      case "1d":
      case "1D":
      default:
        tvTimeframe = "";
        break;
    }
    let normalizedSymbol = symbol.toUpperCase();
    if (normalizedSymbol.includes(":")) {
      normalizedSymbol = normalizedSymbol.split(":")[1];
    }
    let url = "https://scanner.tradingview.com/crypto/scan";
    let ticker = "";
    if (exchange === "BIST") {
      url = "https://scanner.tradingview.com/turkey/scan";
      ticker = `BIST:${normalizedSymbol}`;
    } else {
      if (!normalizedSymbol.endsWith("USDT") && !normalizedSymbol.endsWith("PERP") && !normalizedSymbol.endsWith("USD") && !normalizedSymbol.endsWith("BTC")) {
        normalizedSymbol += "USDT";
      }
      ticker = `${exchange}:${normalizedSymbol}`;
    }
    const requestBody = {
      symbols: {
        tickers: [ticker],
        query: { types: [] }
      },
      columns: [
        `Recommend.All${tvTimeframe}`,
        `Recommend.MA${tvTimeframe}`
      ]
    };
    try {
      const response = await fetch(url, {
        method: "POST",
        body: JSON.stringify(requestBody)
      });
      if (!response.ok) {
        console.warn("TradingView rating fetch failed:", response.status);
        return null;
      }
      const data = await response.json();
      if (data.data && data.data.length > 0 && data.data[0].d) {
        const d = data.data[0].d;
        console.log("\u{1F3F7}\uFE0F Rating data received:", d);
        return {
          technicalRating: d[0] ?? 0,
          maRating: d[1] ?? 0
        };
      }
      return null;
    } catch (error) {
      console.warn("TradingView rating fetch error:", error);
      return null;
    }
  }

