    // ========================================================================
    // Candles
    // ========================================================================
    async getCandles(symbol, interval, limit = 200) {
      const intervalStr = INTERVAL_MAP3[interval] || "60";
      const url = `${BYBIT_REST_URL}/v5/market/kline?category=spot&symbol=${symbol}&interval=${intervalStr}&limit=${Math.min(limit, 200)}`;
      const response = await fetch(url);
      if (!response.ok) throw new Error(`Bybit candle API error: ${response.status}`);
      const data = await response.json();
      if (data.retCode !== 0 || !data.result?.list) {
        throw new Error(`Bybit candle API error: ${data.retMsg}`);
      }
      return data.result.list.reverse().map((c) => ({
        time: Math.floor(parseInt(c[0]) / 1e3),
        open: parseFloat(c[1]),
        high: parseFloat(c[2]),
        low: parseFloat(c[3]),
        close: parseFloat(c[4]),
        volume: parseFloat(c[5])
      }));
    }
    subscribeCandles(symbol, interval, callback) {
      const key = `${symbol}:${interval}`;
      const callbacks = this._candleCallbacks.get(key) || [];
      callbacks.push(callback);
      this._candleCallbacks.set(key, callbacks);
      if (!this._subscriptions.has(`candle:${key}`)) {
        this._subscriptions.add(`candle:${key}`);
        const intervalStr = INTERVAL_MAP3[interval] || "60";
        this._subscribeWs(`kline.${intervalStr}.${symbol}`, (data) => {
          if (data.data?.[0]) {
            const c = data.data[0];
            const candle = {
              time: Math.floor(parseInt(c.start) / 1e3),
              open: parseFloat(c.open),
              high: parseFloat(c.high),
              low: parseFloat(c.low),
              close: parseFloat(c.close),
              volume: parseFloat(c.volume)
            };
            const cbs = this._candleCallbacks.get(key);
            cbs?.forEach((cb) => cb(candle));
          }
        });
      }
    }
    unsubscribeCandles(symbol, interval) {
      const key = `${symbol}:${interval}`;
      this._candleCallbacks.delete(key);
      this._subscriptions.delete(`candle:${key}`);
    }
